      .filter((entry): entry is readonly [string, string] => Boolean(entry[1]))
  );
  const snapshot = createCodexSnapshot(
    this.#runtimeTarget,
    threads,
    archivedListed,
    this.options.workspaceStore.getSnapshot()
  );
